(() => {
  const LIMIT = 4000;

  const title = $json.title ?? '';
  const company = $json.company ?? '';
  const location = $json.location ?? '';
  const salary = $json.salary ?? '';
  const description = $json.description ?? '';

  // Build hyperlinks (Markdown with URL sanitization)
  const links = [];
  for (let i = 1; i <= 10; i++) {
    const rawLink = $json[`link${i}`] ?? null;
    const platform = $json[`application_platform_${i}`] ?? null;
    if (rawLink && platform) {
      try {
        // Prevent broken links from special characters
        const safeLink = encodeURI(rawLink.trim());
        links.push(`[${i}. ${platform}](${safeLink})`);
      } catch (e) {
        // Fallback: output as plain text
        links.push(`${i}. ${platform}: ${rawLink}`);
      }
    }
  }

  const build = (desc) => {
    return [title, company, location, salary, desc, links.join('\n')]
      .map(v => v ?? '')
      .join('\n')
      .replace(/\n{2,}/g, '\n')
      .trim();
  };

  // Try building message with description
  let msg = build(description);
  if (msg.length <= LIMIT) return msg;

  // Drop description if too long
  msg = build('');
  if (msg.length > LIMIT) {
    msg = msg.slice(0, LIMIT - 3) + '...';
  }
  return msg;
})()
}}

