            --text-light: #64748b;
            --a4-width: 210mm;
            --a4-height: 296mm;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; }

        body {
            font-family: 'Inter', sans-serif;
            background-color: #555; 
            color: var(--text-main);
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 20px;
            gap: 20px;
            -webkit-font-smoothing: antialiased;
        }

        .page {
            background: var(--card-bg);
            width: var(--a4-width);
            min-height: var(--a4-height);
